record.field:
today = datetime.date.today()

employees = env['hr.employee'].search([
    ('contract_date_start', '=', today),
    ('active', '=', True),
])

templates = env['mail.template'].search([
    ('name', 'like', '[Onboarding]'),
    ('model', '=', 'hr.employee'),
    ('active', '=', True),
])

if not employees:
    log(f'[Onboarding] No employees starting today ({today})', level='info')
elif not templates:
    log('[Onboarding] No templates found with "[Onboarding]" in name — check Email Templates', level='warning')
else:
    log(f'[Onboarding] Found {len(templates)} template(s): {", ".join(templates.mapped("name"))}', level='info')
    log(f'[Onboarding] {len(employees)} employee(s) starting today: {", ".join(employees.mapped("name"))}', level='info')

    for employee in employees:
        for tmpl in templates:
            try:
                tmpl.send_mail(employee.id, force_send=True)
                log(f'[Onboarding] "{tmpl.name}" sent for {employee.name}', level='info')
            except Exception as e:
                log(f'[Onboarding] ERROR — "{tmpl.name}" for {employee.name}: {e}', level='error')
